    /// <inheritdoc />
    public async Task UploadAsync(string relativeDirPath, IFormFile file)
    {
        var dir = SafeResolve(relativeDirPath);
        Directory.CreateDirectory(dir);

        // IFormFile.FileName is fully client-controlled and cannot be trusted
        // as a path component: combining it verbatim would let values like
        // "../escape.txt" or an absolute path write outside the home root.
        // Reduce to a bare leaf, reject empty/invalid names, and re-verify the
        // resolved path stays within the root before any file is created.
        var path = ResolveChildPath(dir, file.FileName);

        await using var fs = File.Create(path);
        await file.CopyToAsync(fs);
    }

