    private string SafeResolve(string relativePath)
    {
        var root = Root;

        if (string.IsNullOrWhiteSpace(relativePath))
        {
            return root;
        }

        var full = Path.GetFullPath(Path.Combine(root, relativePath));

        var isRoot = string.Equals(full, root, StringComparison.Ordinal);
        var isInsideRoot = full.StartsWith(root + Path.DirectorySeparatorChar, StringComparison.Ordinal);

        if (!isRoot && !isInsideRoot)
        {
            throw new ArgumentException("Invalid path");
        }

        return full;
    }

    /// <summary>
    /// Resolves an untrusted, client-supplied file name to an absolute path
    /// directly under <paramref name="dir"/> (a directory already verified to
    /// be inside the home root). The name is reduced to a bare leaf via
    /// <see cref="Path.GetFileName(string)"/>, which strips leading
    /// directories, ".." segments, drive roots, and absolute paths. Empty or
    /// invalid names are rejected, and the resolved path is re-checked against
    /// the same containment predicate as <see cref="SafeResolve"/> so that a
    /// bare <c>".."</c> (or any other name that still escapes after leafing)
    /// cannot slip through. Throws <see cref="ArgumentException"/> on any
    /// failure.
    /// </summary>
    private string ResolveChildPath(string dir, string fileName)
    {
        var leafName = Path.GetFileName(fileName);
        if (string.IsNullOrWhiteSpace(leafName) || leafName.IndexOfAny(Path.GetInvalidFileNameChars()) >= 0)
        {
            throw new ArgumentException("Invalid file name");
        }

        var root = Root;
        var path = Path.GetFullPath(Path.Combine(dir, leafName));

        var isRoot = string.Equals(path, root, StringComparison.Ordinal);
        var isInsideRoot = path.StartsWith(root + Path.DirectorySeparatorChar, StringComparison.Ordinal);

        if (!isRoot && !isInsideRoot)
        {
            throw new ArgumentException("Invalid file name");
        }

        return path;
    }

